/* FL Scratch-Off Statistician — local browser app over DATA (generated by build_site.py) */
"use strict";
const $=s=>document.querySelector(s);
const G=DATA.games, T=DATA.tiers, W=DATA.winners, M=DATA.meta;
const byNo=Object.fromEntries(G.map(g=>[g.game_no,g]));
const GAME_NAME=Object.fromEntries(G.map(g=>[g.game_no,g.game_name]));

/* ---------- computed metrics (documented in about.html) ---------- */
const clamp=(v,a,b)=>Math.max(a,Math.min(b,v));
for(const g of G){
  const tiers=T[g.game_no]||[];
  // profit odds: chance a ticket pays MORE than it costs (design)
  let pProfit=0,pAnyD=0;
  for(const t of tiers){ if(t[2]>0){ pAnyD+=1/t[2]; if(t[1]>g.ticket_price) pProfit+=1/t[2]; } }
  g.profit_odds=pProfit>0?1/pProfit:null;          // 1-in-X to turn a profit
  g.p_any=g.overall_odds_1_in?1/g.overall_odds_1_in:pAnyD||null;
  // Degenerate odds table (the pipeline withholds EV for exactly these): don't derive profit odds
  // from tiers it distrusts. Keyed off EV-null, NOT data_quality — that field is also set for benign
  // "annuity valued at cash-option" games whose tier tables (and profit odds) are perfectly valid.
  if(g.on_sale&&g.value_per_dollar_now==null){ g.profit_odds=null; if(!g.overall_odds_1_in)g.p_any=null; }
  g.mil_left=tiers.filter(t=>t[1]>=1e6).reduce((s,t)=>s+(t[3]||0),0);   // $1M+ prizes remaining (all tiers)
  g.dead=!!(g.on_sale&&g.top_prizes_total>0&&g.top_prizes_remaining!=null&&g.top_prizes_remaining<=0);
  if(g.top_prizes_remaining!=null&&g.top_prizes_remaining<0)g.top_prizes_remaining=0;  // display clamp (API over-claims)
  g.drift=(g.value_per_dollar_now!=null&&g.value_per_dollar_original!=null)?g.value_per_dollar_now-g.value_per_dollar_original:null;
  // Value Score 0-100 (open formula): 45% current EV, 20% profit-odds, 20% freshness, 15% jackpot health
  if(g.value_per_dollar_now!=null&&g.on_sale){
    const evN=clamp((g.value_per_dollar_now-0.55)/(0.95-0.55),0,1);
    const prN=clamp(((pProfit||0)-0.03)/(0.15-0.03),0,1);
    const frN=clamp((g.pct_value_remaining||0)/100,0,1);
    const jH=g.dead?0:(g.top_prizes_total?clamp(g.top_prizes_remaining/g.top_prizes_total,0,1)*0.5+0.5:0.5);
    g.score=Math.round(100*(0.45*evN+0.20*prN+0.20*frN+0.15*jH));
    if(g.dead)g.score=Math.min(g.score,34);
  } else g.score=null;
  // straight-line projections
  const days=(Date.now()-new Date(g.launch_date||"2024-01-01"))/864e5;
  if(g.on_sale&&g.est_tickets_printed&&g.est_tickets_remaining&&days>14){
    const rate=(g.est_tickets_printed-g.est_tickets_remaining)/days;   // tickets/day
    g.sellout_days=rate>50?Math.round(g.est_tickets_remaining/rate):null;
  } else g.sellout_days=null;
}
const band=s=>s==null?null:s>=70?["Excellent","good"]:s>=55?["Good","teal2"]:s>=40?["Fair","warn"]:["Avoid","bad"];
function scoreBadge(g){
  if(g.score==null)return "—";
  const b=band(g.score);
  return `<span class="scoreb ${b[1]}">${g.score}</span>`;
}
function deadBadge(g){return g.dead?' <span class="deadb">dead money</span>':"";}
// cash haircut per game (avg real payout / advertised) from winners with both numbers
const CASH={};
{const acc={};
 for(const w of W){
   const adv=w[6], pay=w[8]?parseFloat(String(w[8]).replace(/[^\d.]/g,"")):null;
   if(adv>=1e6&&pay&&pay>1000&&w[7]&&/CASH/i.test(w[7])){ (acc[w[0]]=acc[w[0]]||[]).push(pay/adv); }
 }
 for(const k in acc) CASH[k]=acc[k].reduce((a,b)=>a+b,0)/acc[k].length;}


/* ---------- formatting ---------- */
const money=v=>v==null?"—":(v>=1e6?"$"+(v/1e6).toLocaleString(undefined,{maximumFractionDigits:1})+"M":v>=1e3?"$"+(v/1e3).toLocaleString(undefined,{maximumFractionDigits:0})+"k":"$"+Math.round(v).toLocaleString());
const moneyFull=v=>v==null?"—":"$"+Math.round(v).toLocaleString();
const num=v=>v==null?"—":Math.round(v).toLocaleString();
const f2=v=>v==null?"—":(+v).toFixed(2);
const pct=v=>v==null?"—":(+v).toFixed(1)+"%";
const oddsF=v=>v==null?"—":"1 in "+(+v).toLocaleString(undefined,{maximumFractionDigits:2});
const esc=s=>String(s??"").replace(/[&<>"]/g,c=>({"&":"&amp;","<":"&lt;",">":"&gt;",'"':"&quot;"}[c]));
const anon=n=>/EXEMPT/.test(n||"");

/* ---------- extension registry (feature modules in js/ register here) ----------
   FLX.routes[name] = fn(arg)        -> extra hash routes, e.g. #compare/1518,1555
   FLX.gameExtras[] = fn(g)          -> called after game detail renders; append panels to #main
   FLX.ready[]      = fn()           -> called once after first route (data loaded)
   'flx:view' CustomEvent on document after every route: detail={tab,arg}      */
window.FLX={routes:{},gameExtras:[],ready:[],
  css(str){const el=document.createElement("style");el.textContent=str;document.head.appendChild(el);}};

/* ---------- charts registry ---------- */
let charts=[];
function newChart(el,cfg){if(!el||typeof Chart==="undefined")return null;
  // a11y: expose the chart to assistive tech (nearest panel heading as the label)
  try{const h=el.closest(".panel")?.querySelector("h2");
    el.setAttribute("role","img");
    if(!el.getAttribute("aria-label"))el.setAttribute("aria-label",(h?h.textContent.trim():"chart")+" (data visualization)");}catch(e){}
  const c=new Chart(el,cfg);charts.push(c);return c;}
/* a11y: make onclick-only elements keyboard-operable (call after each render) */
const CLICKABLE_SEL=".tix,.more,.ti[data-g],.alertbar[data-g],#mini-dead,.dlcard[data-g],tr.click,.back,.tixpick,.wrec[id],.rt-wpill,.ins-anchor";
function wireA11yClicks(root){
  (root||document).querySelectorAll(CLICKABLE_SEL).forEach(el=>{
    if(el.dataset.a11y||el.matches("a,button,input,select,textarea"))return;
    el.dataset.a11y="1"; if(!el.hasAttribute("tabindex"))el.tabIndex=0;
    if(!el.hasAttribute("role"))el.setAttribute("role","button");
  });
}
document.addEventListener("keydown",e=>{
  if((e.key==="Enter"||e.key===" ")&&e.target instanceof Element&&e.target.dataset&&e.target.dataset.a11y){
    e.preventDefault(); e.target.click();
  }
});
function clearCharts(){charts.forEach(c=>c.destroy());charts=[];}
const gridC="rgba(128,128,128,.15)", tickC=getComputedStyle(document.body).color;
if(typeof Chart!=="undefined"){   // survive a vendor/chart.umd.js load failure: keep tables, router, and the freshness chip alive (charts already no-op via newChart's guard)
  Chart.defaults.color=tickC; Chart.defaults.borderColor=gridC;
  Chart.defaults.font.family=getComputedStyle(document.body).fontFamily;
}

/* ---------- router ---------- */
const mainEl=$("#main");
function go(tab,arg){location.hash=arg?tab+"/"+arg:tab;}
function route(){
  const [tab,arg]=(location.hash.replace(/^#/,"")||"overview").split("/");
  document.querySelectorAll("nav button").forEach(b=>{b.classList.toggle("active",b.dataset.tab===tab);if(b.dataset.tab===tab)b.scrollIntoView({block:"nearest",inline:"center",behavior:"smooth"});});
  $("#nav-game").style.display=(tab==="game")?"":"none";
  clearCharts();
  const builtins={overview,tickets,game,winners,retailers,maps,insights};
  const view=(Object.hasOwn(FLX.routes,tab)?FLX.routes[tab]:undefined)||(Object.hasOwn(builtins,tab)?builtins[tab]:undefined)||overview;  // FLX wins; hasOwn blocks prototype keys
  view(arg);
  document.dispatchEvent(new CustomEvent("flx:view",{detail:{tab,arg}}));
  wireA11yClicks(mainEl);
  window.scrollTo(0,0);
}
window.addEventListener("hashchange",route);
document.querySelectorAll("nav button").forEach(b=>b.onclick=()=>{if(b.dataset.tab!=="game")go(b.dataset.tab);});
/* ---------- data freshness ----------
   Computed in the BROWSER, never baked, so a stale build can't keep claiming "up to date".
   The FL Lottery republishes its numbers each morning in a staggered batch finishing ~6:20am ET;
   this site rebuilds right after. So "up to date" == our data is the Lottery's latest snapshot. */
function freshness(){
  try{
    const dayET=d=>new Intl.DateTimeFormat("en-CA",{timeZone:"America/New_York",year:"numeric",month:"2-digit",day:"2-digit"}).format(d);
    const hourET=d=>+new Intl.DateTimeFormat("en-US",{timeZone:"America/New_York",hour:"numeric",hour12:false}).format(d);
    const now=new Date(), today=dayET(now), yest=dayET(new Date(now-864e5));
    const latestSource=hourET(now)>=7?today:yest;   // before ~7am ET the Lottery's newest is still yesterday's
    const age=Math.round((Date.parse(today)-Date.parse(M.built))/864e5);
    if(M.built>=latestSource) return {s:"ok",label:"up to date"};
    if(age<=1) return {s:"due",label:"today's update is due"};
    return {s:"old",label:`data is ${age} days old`};
  }catch(e){ return {s:"due",label:""}; }
}
(function metaLine(){
  const f=freshness();
  let when="";
  if(M.built_at){const d=new Date(M.built_at); if(!isNaN(d)) when=", "+d.toLocaleTimeString(undefined,{hour:"numeric",minute:"2-digit"});}
  const check='<svg class="ck" width="11" height="11" viewBox="0 0 12 12" aria-hidden="true"><path d="M1.8 6.3l2.7 2.7 5.7-6.1" fill="none" stroke="currentColor" stroke-width="2.1" stroke-linecap="round" stroke-linejoin="round"/></svg>';
  const tip="The Florida Lottery republishes its numbers each morning (finishing about 6:20 AM ET). This site rebuilds itself right after, so these are the freshest figures the Lottery has released. Times shown in your local timezone.";
  $("#meta-line").innerHTML=`${M.n_games} games · ${M.n_winners} top-prize winners · data ${esc(M.built)}${esc(when)}`
    +(f.label?` <span class="fresh ${f.s}" title="${esc(tip)}">${f.s==="ok"?check:""}${esc(f.label)}</span>`:"")
    +(M.winners_stale>0?` <span class="dim">· ${M.winners_stale} game${M.winners_stale>1?"s":""} awaiting a source update</span>`:"");
})();

/* ---------- sortable table helper ---------- */
function makeTable(cols,rows,opts={}){
  // cols: [{k,label,r?,fmt?,sortVal?}]
  let sortK=opts.sort||cols[0].k, dir=opts.dir||-1;
  const outer=document.createElement("div");
  outer.className="tblouter";
  const wrap=document.createElement("div");
  wrap.className="tablewrap";
  const fadeL=document.createElement("div"),fadeR=document.createElement("div");
  fadeL.className="fade fadeL";fadeR.className="fade fadeR";
  const hint=document.createElement("div");
  hint.className="scrollhint";hint.textContent="⟷ table continues — scroll sideways for more columns";
  outer.append(wrap,fadeL,fadeR,hint);
  function updateFades(){
    const more=wrap.scrollWidth-wrap.clientWidth>4;
    fadeR.classList.toggle("show",more&&wrap.scrollLeft<wrap.scrollWidth-wrap.clientWidth-4);
    fadeL.classList.toggle("show",more&&wrap.scrollLeft>4);
    hint.classList.toggle("show",more);
  }
  wrap.addEventListener("scroll",updateFades);
  new ResizeObserver(updateFades).observe(wrap);
  wrap.addEventListener("mouseover",e=>{
    const td=e.target.closest("td");
    if(td&&!td.title&&td.scrollWidth>td.clientWidth)td.title=td.textContent;
  });
  function val(row,c){return c.sortVal?c.sortVal(row):row[c.k];}
  function render(){
    const c0=cols.find(c=>c.k===sortK);
    const sorted=[...rows].sort((a,b)=>{
      const x=val(a,c0),y=val(b,c0);
      if(x==null&&y==null)return 0; if(x==null)return 1; if(y==null)return -1;
      return (typeof x==="string"?x.localeCompare(y):x-y)*dir;
    });
    let h='<table><thead><tr>'+cols.map(c=>`<th class="${c.r?"r":""} ${c.hideM?"hide-m":""}" data-k="${c.k}" role="button" tabindex="0" data-a11y="1" aria-sort="${c.k===sortK?(dir<0?"descending":"ascending"):"none"}">${c.label}${c.k===sortK?` <span class="arr" aria-hidden="true">${dir<0?"▼":"▲"}</span>`:""}</th>`).join("")+'</tr></thead><tbody>';
    for(const row of sorted){
      h+=`<tr${opts.rowClick?` class="click" data-id="${esc(opts.rowClick(row))}" role="button" tabindex="0" data-a11y="1"`:""}>`+
        cols.map(c=>`<td class="${c.r?"r":""} ${c.hideM?"hide-m":""}">${c.fmt?c.fmt(row):esc(row[c.k]??"—")}</td>`).join("")+"</tr>";
    }
    wrap.innerHTML=h+"</tbody></table>";
    wrap.querySelectorAll("th").forEach(th=>th.onclick=()=>{
      const k=th.dataset.k;
      if(k===sortK)dir*=-1; else {sortK=k;dir=-1;}
      render();
    });
    if(opts.rowClick)wrap.querySelectorAll("tr.click").forEach(tr=>tr.onclick=()=>go("game",tr.dataset.id));
    requestAnimationFrame(updateFades);
  }
  render();
  return outer;
}

/* ---------- shared fragments ---------- */
function evCell(g){
  const v=g.value_per_dollar_now;
  if(v==null)return "—";
  const cls=v>=0.8?"good":v<0.7?"bad":"";
  return `<span class="${cls}">${f2(v)}</span>`;
}
function leftBar(g){
  const p=g.pct_value_remaining;
  if(p==null)return "—";
  const cls=p<10?"crit":p<25?"low":"";
  return `<div style="display:flex;align-items:center;gap:8px"><div class="bar ${cls}" style="width:80px"><i style="width:${Math.min(100,p)}%"></i></div><span class="mut">${pct(p)}</span></div>`;
}
function salePill(g){return g.on_sale?'<span class="pill on">on sale</span>':'<span class="pill off">ended</span>';}

const TICKET_COLS=[
  {k:"game_no",label:"#",hideM:1},
  {k:"game_name",label:"Game",fmt:g=>esc(g.game_name)+deadBadge(g)},
  {k:"score",label:"Score",r:1,fmt:scoreBadge},
  {k:"ticket_price",label:"Price",r:1,fmt:g=>"$"+Math.round(g.ticket_price)},
  {k:"top_prize_value_num",label:"Top prize",r:1,fmt:g=>esc(g.top_prize_display||money(g.top_prize_value_num))},
  {k:"top_prizes_remaining",label:"TP left",r:1,hideM:1,fmt:g=>`${g.top_prizes_remaining??"—"}<span class="dim">/${g.top_prizes_total??"—"}</span>`},
  {k:"overall_odds_1_in",label:"Odds",r:1,hideM:1,fmt:g=>g.overall_odds_1_in?("1:"+g.overall_odds_1_in):"—"},
  {k:"profit_odds",label:"Profit odds",r:1,hideM:1,fmt:g=>g.profit_odds?("1 in "+g.profit_odds.toFixed(1)):"—"},
  {k:"value_per_dollar_now",label:"EV/$ now",r:1,fmt:evCell},
  {k:"value_per_dollar_original",label:"EV/$ design",r:1,hideM:1,fmt:g=>f2(g.value_per_dollar_original)},
  {k:"pct_value_remaining",label:"Value left",fmt:leftBar},
  {k:"on_sale",label:"Status",fmt:salePill},
];

/* ================= OVERVIEW ================= */
function overview(){
  const on=G.filter(g=>g.on_sale);
  const tpLeft=on.filter(g=>(g.top_prize_value_num||0)>=1e4).reduce((s,g)=>s+(g.top_prizes_remaining||0),0);
  const valLeft=on.reduce((s,g)=>s+(g.value_remaining||0),0);
  const big=G.filter(g=>g.on_sale&&g.top_prizes_remaining>0&&g.top_prize_value_num>=1e6);
  const bigN=big.reduce((s,g)=>s+g.top_prizes_remaining,0);
  const bestv=[...on].filter(g=>g.value_per_dollar_now!=null).sort((a,b)=>b.value_per_dollar_now-a.value_per_dollar_now);
  const jackv=[...on].filter(g=>g.top_prizes_remaining>0&&g.top_prize_value_num>=1e6).sort((a,b)=>b.top_prize_value_num-a.top_prize_value_num||b.top_prizes_remaining-a.top_prizes_remaining);
  const freshv=[...on].filter(g=>g.pct_value_remaining!=null).sort((a,b)=>b.pct_value_remaining-a.pct_value_remaining);
  const tix=(g,rank,mode)=>{
    let bigv,sm,meta;
    if(mode==="ev"){bigv=f2(g.value_per_dollar_now);sm="EV / $1";meta=`$${Math.round(g.ticket_price)} ticket · ${pct(g.pct_value_remaining)} value left`;}
    else if(mode==="jack"){bigv=money(g.top_prize_value_num);sm=g.top_prizes_remaining+" of "+(g.top_prizes_total||"?")+" left";meta=`$${Math.round(g.ticket_price)} ticket · game #${g.game_no}`;}
    else{bigv=pct(g.pct_value_remaining);sm="value left";meta=`$${Math.round(g.ticket_price)} ticket · EV ${f2(g.value_per_dollar_now)}/$`;}
    return `<div class="tix" data-g="${g.game_no}">
      <div class="rank">${rank}</div>
      <div class="body"><div class="nm">${esc(g.game_name)}</div><div class="meta">${meta}</div></div>
      <div class="big ${mode==="ev"?"good":mode==="jack"?"flamc":""}">${bigv}<small>${sm}</small></div></div>`;
  };
  const posEV=on.filter(g=>g.value_per_dollar_now>1);
  const deadG=on.filter(g=>g.dead).sort((a,b)=>b.ticket_price-a.ticket_price);
  const dl=(DATA.deadlines&&DATA.deadlines.ending)||[];
  const today=new Date(M.built);
  const recent=[...W].filter(w=>w[1]).sort((a,b)=>b[1].localeCompare(a[1])).slice(0,10);
  const tickItems=[
    ...recent.slice(0,6).map(w=>`<span class="ti" data-g="${w[0]}">${money(w[6])} claimed · ${esc(w[3]||"FL")} · ${esc(GAME_NAME[w[0]]||"")}</span>`),
    ...(()=>{const bigs=G.filter(g=>g.on_sale&&g.top_prize_value_num>=5e6&&g.top_prizes_remaining>0);const cnt=bigs.reduce((s,g)=>s+g.top_prizes_remaining,0);return cnt?[`<span class="ti">${cnt} × ${money(Math.max(...bigs.map(g=>g.top_prize_value_num)))}-class jackpots still unclaimed</span>`]:[];})(),
    ...(posEV.length?[`<span class="ti" data-g="${posEV[0].game_no}">${esc(posEV[0].game_name)}: a fragile positive-EV blip — see below</span>`]:[])
  ].join('<span class="tsep">◆</span>');
  mainEl.innerHTML=`
  <div class="ticker" aria-label="recent claims ticker"><div class="tk">${tickItems}<span class="tsep">◆</span>${tickItems}</div></div>
  ${posEV.length?(()=>{const g=posEV[0];const tiers=(T[g.game_no]||[]).filter(t=>t[3]>0);
    const top=tiers.reduce((a,t)=>t[1]>(a?a[1]:-1)?t:a,null);
    const evAfter=(top&&g.est_tickets_remaining&&g.ticket_price)?(g.value_remaining-top[1])/(g.est_tickets_remaining*g.ticket_price):null;
    return `<div class="alertbar" data-g="${g.game_no}"><span class="ab-text"><b>Statistical curiosity:</b>&nbsp;${esc(g.game_name)} ($${Math.round(g.ticket_price)}) is the rare game showing a hair more prize value left than it costs to play (${f2(g.value_per_dollar_now)} per $1)${top?` — but that whole edge rests on <b>${top[3]} unclaimed ${esc(top[0]||money(top[1]))}</b> prize${top[3]>1?"s":""}. The moment one is claimed it drops to about ${evAfter!=null?f2(evAfter):"—"}/$.`:"."} Not a tip: over any real number of tickets, every scratch-off is built to lose.</span></div>`;})():""}
  <div class="ministrip">
    <div class="mini"><b>${on.length}</b><span>games<br>on sale</span></div>
    <div class="mini"><b>${money(valLeft)}</b><span>prize money<br>remaining</span></div>
    <div class="mini"><b>${bigN}</b><span>$1M+ jackpots<br>live in ${big.length} games</span></div>
    <div class="mini"><b>${tpLeft}</b><span>top prizes left<br>($10k+ games)</span></div>
    <div class="mini warnb" id="mini-dead"><b class="bad">${deadG.length}</b><span>dead-money games<br>still on sale ↓</span></div>
  </div>
  <div class="podium">
    <div class="pod"><h3><span class="dot" style="background:var(--teal)"></span>Best value right now</h3>
      <div class="sub">expected payout per $1 of a remaining ticket</div>
      ${bestv.slice(0,3).map((g,i)=>tix(g,i+1,"ev")).join("")}
      <span class="more" data-go="best">full ranking ↓</span></div>
    <div class="pod"><h3><span class="dot" style="background:var(--flamingo)"></span>Biggest jackpots live</h3>
      <div class="sub">advertised top prizes still unclaimed</div>
      ${jackv.slice(0,3).map((g,i)=>tix(g,i+1,"jack")).join("")}
      <span class="more" data-go="jack">all jackpots ↓</span></div>
    <div class="pod"><h3><span class="dot" style="background:var(--tangerine)"></span>Freshest games</h3>
      <div class="sub">most prize value still on the shelf</div>
      ${freshv.slice(0,3).map((g,i)=>tix(g,i+1,"fresh")).join("")}
      <span class="more" data-go="fresh">all fresh games ↓</span></div>
  </div>
  <div class="panel" id="sec-wiz"><h2>Pick a ticket for me</h2>
    <div class="controls">
      <div class="seg" id="wbudget"><button data-v="0" class="active">Any $</button><button data-v="1">$1–2</button><button data-v="5">$3–5</button><button data-v="10">$10</button><button data-v="20">$20–50</button></div>
      <div class="seg" id="wgoal"><button data-v="value" class="active">Best value</button><button data-v="dream">Dream big</button><button data-v="often">Win something</button></div>
    </div>
    <div class="podium" id="wizout"></div>
    <p class="mut" style="font-size:12px">Every scratch-off is negative expected value as designed (rare nearly-sold-out games can briefly turn positive — we flag those above). "Best" here means least-bad by the open <a href="about.html">Value Score formula</a> — no ticket is a good investment.</p>
  </div>
  <div class="panel" id="sec-avoid"><h2>Dead money — avoid <span class="hint">on sale, but the advertised top prize is already gone</span></h2><div id="avoidT"></div></div>
  <div class="panel" id="sec-best"><h2>Best value — full ranking <span class="hint">on-sale games by expected payout per $1</span></h2><div id="best"></div></div>
  <div class="grid2">
    <div class="panel" id="sec-jack"><h2>Biggest jackpots still out there</h2><div id="jack"></div></div>
    <div class="panel" id="sec-fresh"><h2>Freshest games <span class="hint">most prize value left</span></h2><div id="fresh"></div></div>
  </div>
  ${dl.length?`<div class="panel lastchance"><h2>Redemption reminders <span class="hint">friendly heads-up — ended games keep paying until their redemption deadline</span></h2>
    <p class="mut" style="font-size:13px;margin-bottom:10px">If you have old tickets from these ended games lying around, cash them before the deadline. No rush if you don't.</p>
    <div class="dlgrid">${dl.map(d=>{
      const days=Math.ceil((new Date(d.last_redeem)-today)/864e5);
      return `<div class="dlcard"><div class="nm">${esc(d.name)} <span class="dim">$${d.price}</span></div>
        <div class="meta">sales ended ${d.last_sell}</div>
        <div class="cd">${days>0?"redeem by "+d.last_redeem:"expired"}</div>
        <div class="meta">${days>0?days+" days remaining":""}</div></div>`}).join("")}</div></div>`:""}
`;
  mainEl.querySelectorAll(".tix").forEach(t=>t.onclick=()=>go("game",t.dataset.g));
  mainEl.querySelectorAll(".more").forEach(m=>m.onclick=()=>{
    const id={best:"sec-best",jack:"sec-jack",fresh:"sec-fresh"}[m.dataset.go];
    document.getElementById(id)?.scrollIntoView({behavior:"smooth",block:"start"});});
  mainEl.querySelectorAll(".ti[data-g],.alertbar[data-g]").forEach(t=>t.onclick=()=>go("game",t.dataset.g));
  const md=document.getElementById("mini-dead");
  if(md)md.onclick=()=>document.getElementById("sec-avoid")?.scrollIntoView({behavior:"smooth"});
  $("#avoidT").append(makeTable([
    {k:"game_name",label:"Game"},
    {k:"ticket_price",label:"Price",r:1,fmt:g=>"$"+Math.round(g.ticket_price)},
    {k:"top_prize_value_num",label:"Advertised top",r:1,hideM:1,fmt:g=>esc(g.top_prize_display||money(g.top_prize_value_num))},
    {k:"pct_value_remaining",label:"Value left",fmt:leftBar},
    {k:"end_date",label:"On sale until",r:1,hideM:1},
  ],deadG,{sort:"ticket_price",rowClick:g=>g.game_no}));
  const wiz={b:"0",g:"value"};
  function runWiz(){
    let pool=on.filter(g=>g.score!=null&&!g.dead);
    if(wiz.b==="1")pool=pool.filter(g=>g.ticket_price<=2);
    else if(wiz.b==="5")pool=pool.filter(g=>g.ticket_price>=3&&g.ticket_price<=5);
    else if(wiz.b==="10")pool=pool.filter(g=>g.ticket_price===10);
    else if(wiz.b==="20")pool=pool.filter(g=>g.ticket_price>=20);
    if(wiz.g==="dream")pool=[...pool].filter(g=>g.top_prizes_remaining>0).sort((a,b)=>b.top_prize_value_num-a.top_prize_value_num||b.score-a.score);
    else if(wiz.g==="often")pool=[...pool].filter(g=>g.profit_odds).sort((a,b)=>a.profit_odds-b.profit_odds);
    else pool=[...pool].sort((a,b)=>b.score-a.score);
    const why=g=>wiz.g==="dream"?`${esc(g.top_prize_display||money(g.top_prize_value_num))} top prize · ${g.top_prizes_remaining} left`
      :wiz.g==="often"?`1 in ${g.profit_odds.toFixed(1)} tickets turns a profit`
      :`${f2(g.value_per_dollar_now)} back per $1 · ${pct(g.pct_value_remaining)} value left`;
    document.getElementById("wizout").innerHTML=pool.slice(0,3).map((g,i)=>`
      <div class="pod tixpick" data-g="${g.game_no}">
        <h3><span class="dot" style="background:var(--teal)"></span>${["First","Second","Third"][i]} pick ${scoreBadge(g)}</h3>
        <div class="nm2">${esc(g.game_name)}</div>
        <div class="meta">$${Math.round(g.ticket_price)} ticket · ${why(g)}</div></div>`).join("")||'<p class="mut">No games match that filter.</p>';
    document.querySelectorAll(".tixpick").forEach(t=>t.onclick=()=>go("game",t.dataset.g));
  }
  document.querySelectorAll("#wbudget button").forEach(b=>b.onclick=()=>{wiz.b=b.dataset.v;document.querySelectorAll("#wbudget button").forEach(x=>x.classList.toggle("active",x===b));runWiz();});
  document.querySelectorAll("#wgoal button").forEach(b=>b.onclick=()=>{wiz.g=b.dataset.v;document.querySelectorAll("#wgoal button").forEach(x=>x.classList.toggle("active",x===b));runWiz();});
  runWiz();
  $("#best").append(makeTable(TICKET_COLS,on.filter(g=>g.value_per_dollar_now!=null),{sort:"value_per_dollar_now",rowClick:g=>g.game_no}));
  const jrows=G.filter(g=>g.top_prizes_remaining>0&&g.top_prize_value_num>=2e6).map(g=>g);
  $("#jack").append(makeTable([
    {k:"game_name",label:"Game"},
    {k:"top_prize_value_num",label:"Top prize",r:1,fmt:g=>esc(g.top_prize_display||money(g.top_prize_value_num))},
    {k:"top_prizes_remaining",label:"Left",r:1},
    {k:"ticket_price",label:"Price",r:1,fmt:g=>"$"+Math.round(g.ticket_price)},
    {k:"on_sale",label:"",fmt:salePill},
  ],jrows,{sort:"top_prize_value_num",rowClick:g=>g.game_no}));
  $("#fresh").append(makeTable([
    {k:"game_name",label:"Game"},
    {k:"launch_date",label:"Launched"},
    {k:"pct_value_remaining",label:"Value left",fmt:leftBar},
    {k:"value_per_dollar_now",label:"EV/$",r:1,fmt:evCell},
  ],G.filter(g=>g.on_sale&&g.pct_value_remaining!=null),{sort:"pct_value_remaining",rowClick:g=>g.game_no}));
}

/* ================= ALL TICKETS ================= */
function tickets(){
  mainEl.innerHTML=`
  <div class="panel"><h2>All ${G.length} tickets</h2>
    <div class="controls">
      <input type="text" id="q" placeholder="Search game name or #…">
      <select id="price"><option value="">Any price</option>${[...new Set(G.map(g=>g.ticket_price))].sort((a,b)=>a-b).map(p=>`<option>${Math.round(p)}</option>`).join("")}</select>
      <div class="seg" id="sale"><button data-v="" class="active">All</button><button data-v="1">On sale</button><button data-v="0">Ended</button></div>
    </div>
    <div id="tbl"></div>
    <div class="sortnote">Click any column to sort · click a row for full game detail</div>
  </div>`;
  let q="",price="",sale="";
  function refresh(){
    const rows=G.filter(g=>
      (!q||g.game_name.toLowerCase().includes(q)||g.game_no.includes(q))&&
      (!price||Math.round(g.ticket_price)===+price)&&
      (sale===""||String(g.on_sale)===sale));
    $("#tbl").innerHTML="";
    $("#tbl").append(makeTable(TICKET_COLS,rows,{sort:"value_per_dollar_now",rowClick:g=>g.game_no}));
  }
  $("#q").oninput=e=>{q=e.target.value.toLowerCase();refresh();};
  $("#price").onchange=e=>{price=e.target.value;refresh();};
  document.querySelectorAll("#sale button").forEach(b=>b.onclick=()=>{
    sale=b.dataset.v;document.querySelectorAll("#sale button").forEach(x=>x.classList.toggle("active",x===b));refresh();});
  refresh();
}

/* ================= GAME DETAIL ================= */
function game(no){
  const g=byNo[no];
  if(!g){mainEl.innerHTML='<div class="panel">Unknown game.</div>';return;}
  const tiers=T[no]||[];
  const gw=W.filter(w=>w[0]===no);
  const flag=g.data_quality?`<div class="flagnote">Note: ${esc(g.data_quality)}</div>`:"";
  mainEl.innerHTML=`
  <span class="back" onclick="history.back()">← back</span>
  <div class="gtitle">${esc(g.game_name)} <span class="dim">#${g.game_no}</span> ${salePill(g)}${deadBadge(g)} ${g.score!=null?scoreBadge(g):""}</div>
  <div class="gsub">$${Math.round(g.ticket_price)} ticket · top prize ${esc(g.top_prize_display||money(g.top_prize_value_num))}${CASH[no]&&g.top_prize_value_num>=1e6?` <span class="dim">(winners actually take ≈ ${money(g.top_prize_value_num*CASH[no])} cash)</span>`:""} · overall odds 1:${g.overall_odds_1_in??"?"}${g.profit_odds?` · profit odds 1 in ${g.profit_odds.toFixed(1)}`:""} · launched ${g.launch_date||"?"}${g.on_sale?"":" · ended "+g.end_date+(g.redemption_date?" · redeem by "+g.redemption_date:"")} · data ${esc(g.last_queried||"")}</div>
  ${g.mil_left>0?`<div class="gsub" style="margin-top:-8px"><b class="flamc">${g.mil_left}</b> prizes of $1,000,000+ still unclaimed in this game${g.sellout_days?` · at the current sales pace, est. sold out in ~${g.sellout_days>365?Math.round(g.sellout_days/30)+" months":g.sellout_days+" days"}`:""}</div>`:(g.sellout_days&&g.on_sale?`<div class="gsub" style="margin-top:-8px">est. sold out in ~${g.sellout_days>365?Math.round(g.sellout_days/30)+" months":g.sellout_days+" days"} at current pace</div>`:"")}
  ${flag}
  ${(g.on_sale&&g.value_per_dollar_now>=1)?(()=>{const tp=tiers.filter(t=>t[3]>0).reduce((a,t)=>t[1]>(a?a[1]:-1)?t:a,null);
    const evAfter=(tp&&g.est_tickets_remaining&&g.ticket_price)?(g.value_remaining-tp[1])/(g.est_tickets_remaining*g.ticket_price):null;
    return `<div class="flagnote" style="background:rgba(47,182,168,.1);border-color:rgba(47,182,168,.4);color:var(--text)"><b>Read the EV below carefully — it is not a tip.</b> This game shows more prize value left than it costs to play only because it is ${pct(g.pct_value_remaining)} sold through with ${tp?`${tp[3]} unclaimed ${esc(tp[0]||money(tp[1]))} prize${tp[3]>1?"s":""}`:"a big prize"} still live. The instant one is claimed the EV drops to about ${evAfter!=null?f2(evAfter):"—"}/$. Over any real number of tickets you will lose money — every scratch-off is built to.</div>`;})():""}
  <div class="cards">
    <div class="card"><div class="lab">EV per $1 now</div><div class="val ${g.value_per_dollar_now>=0.8?"good":""}">${f2(g.value_per_dollar_now)}</div><div class="note">design ${f2(g.value_per_dollar_original)}</div></div>
    <div class="card"><div class="lab">Top prizes left</div><div class="val">${g.top_prizes_remaining??"—"} <span class="dim" style="font-size:15px">of ${g.top_prizes_total??"—"}</span></div></div>
    <div class="card"><div class="lab">Prize value left</div><div class="val">${money(g.value_remaining)}</div><div class="note">${pct(g.pct_value_remaining)} of ${money(g.value_original)}</div></div>
    <div class="card"><div class="lab">Est. tickets left</div><div class="val">${num(g.est_tickets_remaining)}</div><div class="note">of ~${num(g.est_tickets_printed)}</div></div>
  </div>
  <div class="grid2">
    <div class="panel"><h2>Prize tiers <span class="hint">official odds &amp; live counts</span></h2><div id="tierT"></div></div>
    <div class="panel"><h2>Tier depletion <span class="hint">% of each tier already claimed</span></h2><div class="chartbox"><canvas id="depC"></canvas></div></div>
  </div>
  <div class="panel"><h2>Top-prize winners on this game (${gw.length})</h2><div id="winT">${gw.length?"":'<span class="mut">None claimed yet.</span>'}</div></div>`;
  const trows=tiers.map(t=>({disp:t[0],val:t[1],odds:t[2],rem:t[3],orig:t[4],claimed:t[5]}));
  $("#tierT").append(makeTable([
    {k:"disp",label:"Prize",sortVal:r=>r.val},
    {k:"odds",label:"Odds",r:1,fmt:r=>oddsF(r.odds)},
    {k:"rem",label:"Remaining",r:1,fmt:r=>num(r.rem)},
    {k:"orig",label:"Original",r:1,fmt:r=>num(r.orig)},
    {k:"claimed",label:"% claimed",r:1,fmt:r=>r.orig?((100*r.claimed/r.orig).toFixed(1)+"%"):"—"},
  ],trows,{sort:"disp",dir:-1}));
  newChart($("#depC"),{type:"bar",data:{
    labels:trows.map(r=>r.disp),
    datasets:[{label:"% claimed",data:trows.map(r=>r.orig?100*r.claimed/r.orig:0),backgroundColor:"#E24B5B"},
              {label:"% remaining",data:trows.map(r=>r.orig?100*r.rem/r.orig:0),backgroundColor:"#2FB6A8"}]},
    options:{indexAxis:"y",responsive:true,maintainAspectRatio:false,
      scales:{x:{stacked:true,max:100,ticks:{callback:v=>v+"%"}},y:{stacked:true}},
      plugins:{legend:{position:"bottom"}}}});
  FLX.gameExtras.forEach(f=>{try{f(g)}catch(e){console.warn("gameExtra failed",e)}});
  if(gw.length){
    $("#winT").append(makeTable([
      {k:"1",label:"Claimed",fmt:w=>w[1]||"—",sortVal:w=>w[1]||""},
      {k:"2",label:"Winner",fmt:w=>anon(w[2])?'<span class="dim">anonymous (90-day exemption)</span>':esc(w[2]),sortVal:w=>w[2]},
      {k:"3",label:"City",fmt:w=>esc(w[3]||"—"),sortVal:w=>w[3]||""},
      {k:"5",label:"Prize",r:1,fmt:w=>esc(w[5]),sortVal:w=>w[6]},
      {k:"8",label:"Payout",r:1,hideM:1,fmt:w=>esc(w[8]||"—"),sortVal:w=>w[8]||""},
      {k:"10",label:"Sold at",fmt:w=>esc(w[10]||"—"),sortVal:w=>w[10]||""},
    ],gw,{sort:"1"}));
  }
}

/* ================= WINNERS ================= */
function winners(){
  mainEl.innerHTML=`
  <div class="panel"><h2>All top-prize winners (${W.length})</h2>
    <div class="controls">
      <input type="text" id="wq" placeholder="Search name, city, retailer, game…">
      <select id="wmin"><option value="0">Any prize</option><option value="250000">$250k+</option><option value="1000000">$1M+</option><option value="5000000">$5M+</option></select>
      <select id="wanon"><option value="">Named + anonymous</option><option value="named">Named only</option><option value="anon">Anonymous only</option></select>
    </div>
    <div id="wtbl"></div>
  </div>`;
  let q="",min=0,anonF="";
  function refresh(){
    const rows=W.filter(w=>
      (!q||[w[2],w[3],w[10],GAME_NAME[w[0]],w[0]].some(x=>(x||"").toLowerCase().includes(q)))&&
      ((w[6]||0)>=min)&&(anonF===""||(anonF==="named"?!anon(w[2]):anon(w[2]))));
    $("#wtbl").innerHTML="";
    $("#wtbl").append(makeTable([
      {k:"1",label:"Claimed",fmt:w=>w[1]||"—",sortVal:w=>w[1]||""},
      {k:"0",label:"Game",fmt:w=>`${esc(GAME_NAME[w[0]]||w[0])} <span class="dim">#${w[0]}</span>`,sortVal:w=>GAME_NAME[w[0]]||""},
      {k:"2",label:"Winner",fmt:w=>anon(w[2])?'<span class="dim">anonymous</span>':esc(w[2]),sortVal:w=>w[2]},
      {k:"3",label:"City",fmt:w=>esc(w[3]||"—"),sortVal:w=>w[3]||""},
      {k:"6",label:"Prize",r:1,fmt:w=>esc(w[5]),sortVal:w=>w[6]},
      {k:"8",label:"Payout",r:1,hideM:1,fmt:w=>esc(w[8]||"—"),sortVal:w=>w[8]||""},
      {k:"10",label:"Sold at",fmt:w=>esc((w[10]||"—")+(w[11]?" — "+w[11]:"")),sortVal:w=>w[10]||""},
    ],rows,{sort:"1"}));
  }
  $("#wq").oninput=e=>{q=e.target.value.toLowerCase();refresh();};
  $("#wmin").onchange=e=>{min=+e.target.value;refresh();};
  $("#wanon").onchange=e=>{anonF=e.target.value;refresh();};
  refresh();
}

/* ================= RETAILERS ================= */
function retailers(){
  const R=DATA.retail;
  if(!R){mainEl.innerHTML='<div class="panel">Retailer census not available in this build.</div>';return;}
  const topChain=R.chains[0];
  mainEl.innerHTML=`
  <div class="cards">
    <div class="card"><div class="lab">FL lottery retailers</div><div class="val">${num(R.total)}</div><div class="note">full statewide census</div></div>
    <div class="card"><div class="lab">Self-service vending</div><div class="val">${num(R.itvm)}</div><div class="note">${(100*R.itvm/R.total).toFixed(0)}% have a machine</div></div>
    <div class="card"><div class="lab">Publix locations</div><div class="val">${num(R.chains.find(c=>c.name==="Publix")?.stores)}</div><div class="note">most of any chain</div></div>
    <div class="card flam"><div class="lab">Base win rate</div><div class="val">${R.base_per1k}</div><div class="note">top-prize winners / 1,000 stores</div></div>
  </div>
  <div class="panel insight"><h2>Is any store "luckier"? <span class="hint">the honest answer</span></h2>
    <p class="mut" style="font-size:13.5px">No. Every top-prize winner is a random draw from tickets <em>sold</em>, so raw winner counts just track <b>sales volume</b>. To compare fairly we divide winners by each chain's actual store count (a real denominator from the ${num(R.total)}-store census). Even this is a rough proxy — it assumes every store sells the same volume — but it's far better than raw counts. Read <b>lift</b> as "winners per store vs. the statewide average": <b>1.0× = average</b>, above = more winners per location (i.e. more tickets sold there), below = fewer.</p></div>
  <div class="grid2">
    <div class="panel"><h2>By chain <span class="hint">winners per 1,000 stores vs. average</span></h2><div id="chainT"></div></div>
    <div class="panel"><h2>By store type</h2><div id="typeT"></div>
      <p class="mut" style="font-size:12.5px;margin-top:10px">Gas/convenience has the most winners overall only because Florida has ~${(R.types.find(t=>/Gas/.test(t.name))?.stores/1000).toFixed(1)}k of them. <b>Per store, supermarkets win ${(R.types.find(t=>/Grocery/.test(t.name))?.lift/R.types.find(t=>/Gas/.test(t.name))?.lift).toFixed(1)}× as often</b> — the "gas stations are luckier" idea is backwards.</p>
    </div>
  </div>`;
  const liftCell=r=>{const c=r.lift>=1.3?"good":r.lift<=0.7?"bad":"mut";return `<span class="lift ${c}">${r.lift.toFixed(2)}×</span>`;};
  $("#chainT").append(makeTable([
    {k:"name",label:"Chain"},
    {k:"stores",label:"FL stores",r:1,fmt:r=>num(r.stores)},
    {k:"winners",label:"Winners",r:1},
    {k:"per1k",label:"Per 1k stores",r:1,fmt:r=>r.per1k.toFixed(1)},
    {k:"lift",label:"Lift",r:1,fmt:liftCell},
  ],R.chains,{sort:"lift"}));
  $("#typeT").append(makeTable([
    {k:"name",label:"Type"},
    {k:"stores",label:"Stores",r:1,fmt:r=>num(r.stores)},
    {k:"winners",label:"Winners",r:1},
    {k:"per1k",label:"Per 1k",r:1,fmt:r=>r.per1k.toFixed(1)},
    {k:"lift",label:"Lift",r:1,fmt:liftCell},
  ],R.types,{sort:"lift"}));
}

/* ================= MAPS ================= */
function maps(){
  mainEl.innerHTML=`
  <div class="panel">
    <h2>Winner geography</h2>
    <div class="controls">
      <div class="seg" id="mmode"><button data-m="home" class="active">Winner homes</button><button data-m="ret">Where sold</button></div>
      <span class="mut" id="mcap"></span>
    </div>
    <div class="legend">
      <span class="mut">biggest prize:</span>
      <span><span class="sw" style="background:#E24B5B"></span>$25M</span>
      <span><span class="sw" style="background:#FF9E4A"></span>$5M+</span>
      <span><span class="sw" style="background:#FF6F91"></span>$2M</span>
      <span><span class="sw" style="background:#2FB6A8"></span>$1M</span>
      <span><span class="sw" style="background:#7d8f87"></span>&lt;$1M</span>
      <span class="mut">· circle size = winners in that city · hover for detail</span>
    </div>
    <div id="map-wrap"><div id="map"></div><div id="tip"></div></div>
  </div>`;
  const COL=[null,"#7d8f87","#2FB6A8","#FF6F91","#FF9E4A","#E24B5B"];
  const Wd=760,Hd=620;
  const svg=d3.select("#map").append("svg").attr("viewBox",`0 0 ${Wd} ${Hd}`).attr("width","100%").attr("role","img").attr("aria-label","Map of Florida showing top-prize winner locations by city");
  const proj=d3.geoMercator().fitExtent([[14,14],[Wd-14,Hd-14]],DATA.fl);
  const dark=matchMedia("(prefers-color-scheme: dark)").matches;
  svg.append("path").datum(DATA.fl).attr("d",d3.geoPath(proj))
     .attr("fill",dark?"#183029":"#ece2cf").attr("stroke",dark?"#2b433c":"#d7cbb3");
  const layer=svg.append("g");
  const tip=$("#tip"),wrap=$("#map-wrap");
  let mode="home";
  function draw(){
    const rows=(mode==="home"?DATA.map_home:DATA.map_ret).slice().sort((a,b)=>b[2]-a[2]);
    const tot=rows.reduce((s,r)=>s+r[2],0);
    $("#mcap").textContent=mode==="home"
      ?`${tot} winners across ${rows.length} home cities`
      :`${tot} winning tickets across ${rows.length} store cities`;
    layer.selectAll("circle").data(rows,r=>r[4]).join("circle")
      .attr("cx",r=>{const p=proj([r[0],r[1]]);return p?p[0]:-99;})
      .attr("cy",r=>{const p=proj([r[0],r[1]]);return p?p[1]:-99;})
      .attr("r",r=>3+Math.sqrt(r[2])*2).attr("fill",r=>COL[r[3]])
      .attr("fill-opacity",.72).attr("stroke",dark?"#111":"#fff").attr("stroke-width",.6)
      .on("mousemove",(ev,r)=>{
        const b=wrap.getBoundingClientRect();
        tip.innerHTML=`<b>${esc(r[4])}</b><br>${r[2]} ${mode==="home"?"winners":"tickets sold"}<br>biggest: ${money(r[5])}`;
        tip.style.opacity=1;
        let x=ev.clientX-b.left+14,y=ev.clientY-b.top+12;
        if(x>b.width-170)x-=190; tip.style.left=x+"px";tip.style.top=y+"px";})
      .on("mouseleave",()=>tip.style.opacity=0);
  }
  document.querySelectorAll("#mmode button").forEach(b=>b.onclick=()=>{
    mode=b.dataset.m;document.querySelectorAll("#mmode button").forEach(x=>x.classList.toggle("active",x===b));draw();});
  draw();
  // county table
  if(DATA.counties.length){
    const p=document.createElement("div");p.className="panel";
    p.innerHTML=`<h2>County analysis <span class="hint">winners vs population — index 1.0 = exactly proportional</span></h2><div id="cT"></div>`;
    mainEl.append(p);
    $("#cT").append(makeTable([
      {k:"county",label:"County"},
      {k:"pop",label:"Population",r:1,fmt:r=>num(r.pop)},
      {k:"winners",label:"Winners",r:1},
      {k:"per100k",label:"Per 100k",r:1},
      {k:"expected",label:"Expected",r:1},
      {k:"index",label:"Index",r:1,fmt:r=>r.index==null?"—":`<span class="${r.index>=1.5?"good":r.index<=0.6&&r.pop>200000?"bad":""}">${r.index.toFixed(2)}×</span>`},
    ],DATA.counties,{sort:"winners"}));
  }
}

/* ================= INSIGHTS ================= */
function insights(){
  mainEl.innerHTML=`
  <div class="panel insight"><h2>How to read this</h2>
    <p class="mut" style="font-size:13.5px">Every scratch-off is negative-EV as designed — rare nearly-sold-out games can briefly turn positive on remaining tickets. <b>Which game</b> you pick matters far more than which price tier: payout is ~75% at every price point. The jackpot is marketing: it typically holds under a tenth of a game's prize value. Cash-option payouts run roughly 60–65% of advertised face for big prizes.</p></div>
  <div class="grid2">
    <div class="panel"><h2>EV vs price <span class="hint">every on-sale game</span></h2><div class="chartbox"><canvas id="scat"></canvas></div></div>
    <div class="panel"><h2>Design payout by price tier</h2><div class="chartbox"><canvas id="payp"></canvas></div></div>
  </div>
  <div class="grid2">
    <div class="panel"><h2>The buy zone <span class="hint">value now vs freshness — top-right is where you want to shop</span></h2><div class="chartbox"><canvas id="quad"></canvas></div></div>
    <div class="panel"><h2>EV drift <span class="hint">how each game's value moved since it was designed</span></h2><div class="chartbox"><canvas id="drift"></canvas></div></div>
  </div>
  <div class="grid2">
    <div class="panel"><h2>The anonymity era <span class="hint">share of winners hidden by F.S. 24.1051 (90-day shield, from Apr 2026)</span></h2><div class="chartbox"><canvas id="anonC"></canvas></div></div>
    <div class="panel"><h2>Top-prize claims over time</h2><div class="chartbox"><canvas id="tline"></canvas></div></div>
    <div class="panel"><h2>Where the prize money sits <span class="hint">remaining value by tier size, all on-sale games</span></h2><div class="chartbox"><canvas id="split"></canvas></div></div>
  </div>`;
  const on=G.filter(g=>g.on_sale&&g.value_per_dollar_now!=null);
  newChart($("#scat"),{type:"scatter",data:{datasets:[{
      data:on.map(g=>({x:g.ticket_price,y:g.value_per_dollar_now,g})),
      pointRadius:5,pointHoverRadius:7,
      pointBackgroundColor:on.map(g=>g.value_per_dollar_now>=0.8?"#2FB6A8":g.value_per_dollar_now<0.7?"#E24B5B":"#FF9E4A")}]},
    options:{responsive:true,maintainAspectRatio:false,
      plugins:{legend:{display:false},tooltip:{callbacks:{
        label:c=>`${c.raw.g.game_name} (#${c.raw.g.game_no}): ${f2(c.raw.y)}/$ at $${Math.round(c.raw.x)}`}}},
      scales:{x:{title:{display:true,text:"ticket price ($)"},type:"linear"},
              y:{title:{display:true,text:"EV per $1 (now)"}}},
      onClick:(ev,els,chart)=>{if(els.length){go("game",chart.data.datasets[0].data[els[0].index].g.game_no);}}}});
  const prices=[...new Set(G.filter(g=>g.value_per_dollar_original!=null).map(g=>Math.round(g.ticket_price)))].sort((a,b)=>a-b);
  const avg=prices.map(p=>{const s=G.filter(g=>Math.round(g.ticket_price)===p&&g.value_per_dollar_original!=null);return s.reduce((t,g)=>t+g.value_per_dollar_original,0)/s.length;});
  newChart($("#payp"),{type:"bar",data:{labels:prices.map(p=>"$"+p),
      datasets:[{label:"avg design payout",data:avg.map(v=>+(100*v).toFixed(1)),backgroundColor:"#2FB6A8"}]},
    options:{responsive:true,maintainAspectRatio:false,
      plugins:{legend:{display:false},tooltip:{callbacks:{label:c=>c.raw+"% designed payout"}}},
      scales:{y:{min:50,max:85,ticks:{callback:v=>v+"%"}}}}});
  // buy-zone quadrant
  newChart($("#quad"),{type:"scatter",data:{datasets:[{
      data:on.filter(g=>g.pct_value_remaining!=null).map(g=>({x:g.pct_value_remaining,y:g.value_per_dollar_now,g})),
      pointRadius:on.map(g=>3+Math.sqrt(g.ticket_price||1)*1.4),pointHoverRadius:9,
      pointBackgroundColor:on.map(g=>g.value_per_dollar_now>=0.78&&g.pct_value_remaining>=40?"#2FB6A8":g.dead?"#E24B5B":"#7d8f87")}]},
    options:{responsive:true,maintainAspectRatio:false,
      plugins:{legend:{display:false},tooltip:{callbacks:{label:c=>`${c.raw.g.game_name}: ${f2(c.raw.y)}/$ · ${pct(c.raw.x)} left · $${Math.round(c.raw.g.ticket_price)}`}}},
      scales:{x:{title:{display:true,text:"% of prize value remaining"},min:0,max:100},
              y:{title:{display:true,text:"EV per $1 now"}}},
      onClick:(e,els,ch)=>{if(els.length)go("game",ch.data.datasets[0].data[els[0].index].g.game_no);}}});
  // EV drift diverging bars
  const dr=[...on].filter(g=>g.drift!=null).sort((a,b)=>b.drift-a.drift);
  const drTop=[...dr.slice(0,7),...dr.slice(-7)];
  newChart($("#drift"),{type:"bar",data:{labels:drTop.map(g=>g.game_name.slice(0,22)),
      datasets:[{data:drTop.map(g=>+(g.drift).toFixed(3)),
        backgroundColor:drTop.map(g=>g.drift>=0?"#2FB6A8":"#E24B5B")}]},
    options:{indexAxis:"y",responsive:true,maintainAspectRatio:false,
      plugins:{legend:{display:false},tooltip:{callbacks:{label:c=>`${c.raw>=0?"+":""}${c.raw} EV/$ vs design`}}},
      scales:{x:{title:{display:true,text:"EV per $1: now − design"}},y:{ticks:{font:{size:10.5}}}},
      onClick:(e,els)=>{if(els.length)go("game",drTop[els[0].index].game_no);}}});
  // anonymity era
  const am={};
  for(const w of W){ if(w[1]&&w[1]>="2025-07"){const m=w[1].slice(0,7);(am[m]=am[m]||[0,0])[0]++;if(anon(w[2]))am[m][1]++;}}
  const ams=Object.keys(am).sort();
  newChart($("#anonC"),{type:"bar",data:{labels:ams,
      datasets:[{label:"% anonymous",data:ams.map(m=>+(100*am[m][1]/am[m][0]).toFixed(0)),backgroundColor:ams.map(m=>m>="2026-04"?"#FF6F91":"#7d8f87")}]},
    options:{responsive:true,maintainAspectRatio:false,
      plugins:{legend:{display:false},tooltip:{callbacks:{label:c=>c.raw+"% of that month's winners are anonymous"}}},
      scales:{y:{min:0,max:100,ticks:{callback:v=>v+"%"}},x:{ticks:{maxRotation:60}}}}});
  const tl=DATA.timeline.filter(t=>t[0]>="2022-10");
  newChart($("#tline"),{type:"bar",data:{labels:tl.map(t=>t[0]),
      datasets:[{label:"claims",data:tl.map(t=>t[1]),backgroundColor:"#FF6F91"}]},
    options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{display:false}},
      scales:{x:{ticks:{maxRotation:60,autoSkip:true,maxTicksLimit:20}}}}});
  // remaining value split
  let buckets={"jackpot tier":0,"$10k–$1M":0,"$1k–$10k":0,"under $1k":0};
  for(const g of G.filter(g=>g.on_sale)){
    (T[g.game_no]||[]).forEach((t,i)=>{
      const v=t[1]*(t[3]||0);
      if(i===0)buckets["jackpot tier"]+=v;
      else if(t[1]>=1e4)buckets["$10k–$1M"]+=v;
      else if(t[1]>=1e3)buckets["$1k–$10k"]+=v;
      else buckets["under $1k"]+=v;});
  }
  newChart($("#split"),{type:"doughnut",data:{labels:Object.keys(buckets),
      datasets:[{data:Object.values(buckets).map(v=>Math.round(v/1e6)),
        backgroundColor:["#E24B5B","#FF9E4A","#FF6F91","#2FB6A8"],borderWidth:0}]},
    options:{responsive:true,maintainAspectRatio:false,
      plugins:{legend:{position:"bottom"},tooltip:{callbacks:{label:c=>` ${c.label}: $${c.raw}M remaining`}}}}});
}

function boot(){route();FLX.ready.forEach(f=>{try{f()}catch(e){console.warn("ready hook failed",e)}});}
// defer first route to DOMContentLoaded so deferred feature modules register their hooks first
if(document.readyState==="loading")document.addEventListener("DOMContentLoaded",boot);else boot();
